#!/usr/bin/env bash
dropbear_manage(){
 while true; do header 'GERENCIAR DROPBEAR'; local p; p=$(grep -E '^DROPBEAR_PORT=' /etc/default/dropbear 2>/dev/null|cut -d= -f2);p=${p:-109};echo "PORTA: $p";echo '1) Instalar/configurar';echo '2) Alterar porta';echo '3) Reiniciar';echo '4) Parar';echo '5) Status/Logs';echo '6) Remover';echo '0) Voltar';read -r -p 'Opção: ' o
 case $o in 1|2)read -r -p "Porta [$p]: " np;np=${np:-$p};require_free_port "$np" dropbear||{ pause;continue;};apt-get install -y dropbear;local f=/etc/default/dropbear bak;bak="$f.bak.$(date +%s)";cp -a "$f" "$bak" 2>/dev/null||true;sed -i 's/^NO_START=.*/NO_START=0/' "$f";grep -q '^DROPBEAR_PORT=' "$f"&&sed -i "s/^DROPBEAR_PORT=.*/DROPBEAR_PORT=$np/" "$f"||echo "DROPBEAR_PORT=$np">>"$f";if systemctl enable --now dropbear&&systemctl restart dropbear;then ufw allow "$np/tcp" 2>/dev/null||true;ok 'Dropbear configurado';else cp -af "$bak" "$f";systemctl restart dropbear 2>/dev/null||true;warn 'Rollback aplicado';fi;pause;;3)systemctl restart dropbear;pause;;4)systemctl stop dropbear;pause;;5)systemctl status dropbear --no-pager||true;journalctl -u dropbear -n 80 --no-pager;pause;;6)systemctl disable --now dropbear 2>/dev/null||true;apt-get purge -y dropbear;pause;;0)return;;esac;done
}
